const float RNNModel::den1_b[1] = {0.20864086f};


RNNModel::RNNModel() {}

float RNNModel::predict(const float* input, int seq_len) {

    // Reset per-layer hidden (and cell) states
    for (int i = 0; i < 32; i++) { h0[i] = 0.0f; }
    for (int i = 0; i < 32; i++) { h1[i] = 0.0f; }

    // ================================================================
    // Recurrent pass
    // ================================================================
    for (int t = 0; t < seq_len; t++) {
        const float* x_t = input + t * 2;

        // ---- RNN layer 0  in=2 hidden=32 act=tanh ----
        for (int k = 0; k < 32; k++) {
            float acc = rec0_W_ih_b[k];
            for (int j = 0; j < 2; j++)
                acc += rec0_W_ih_w[k][j] * x_t[j];
            for (int j = 0; j < 32; j++)
                acc += rec0_W_hh_w[k][j] * h0[j];
            acc += rec0_W_hh_b[k];
            acc = tanhf(acc);
            h0_new[k] = acc;
        }
        for (int k = 0; k < 32; k++) h0[k] = h0_new[k];
        x_t = h0;

        // ---- RNN layer 1  in=32 hidden=32 act=tanh ----
        for (int k = 0; k < 32; k++) {
            float acc = rec1_W_ih_b[k];
            for (int j = 0; j < 32; j++)
                acc += rec1_W_ih_w[k][j] * x_t[j];
            for (int j = 0; j < 32; j++)
                acc += rec1_W_hh_w[k][j] * h1[j];
            acc += rec1_W_hh_b[k];
            acc = tanhf(acc);
            h1_new[k] = acc;
        }
        for (int k = 0; k < 32; k++) h1[k] = h1_new[k];
        x_t = h1;

    } // end time-step loop

    // ================================================================
    // Dense head
    // ================================================================
    // Dense layer 0  in=32 out=16 act=relu
    for (int k = 0; k < 16; k++) {
        float acc = den0_b[k];
        for (int j = 0; j < 32; j++)
            acc += den0_w[k][j] * h1[j];
        if (acc < 0.0f) acc = 0.0f;
        dense_out[k] = acc;
    }
    for (int k = 0; k < 16; k++) dense_in[k] = dense_out[k];

    // Dense layer 1  in=16 out=1 act=linear
    for (int k = 0; k < 1; k++) {
        float acc = den1_b[k];
        for (int j = 0; j < 16; j++)
            acc += den1_w[k][j] * dense_in[j];
        dense_out[k] = acc;
    }

    return dense_out[0];
}